import { Workflow, measure } from 'mastra/workflows';

const latencyProfiler = (workflow: Workflow) => {
  const originalStep = workflow.executeStep;
  workflow.executeStep = async (stepId: string, input: any) => {
    const start = performance.now();
    const result = await originalStep.call(workflow, stepId, input);
    const duration = performance.now() - start;

    if (duration > 5000) { // Flag steps > 5s
      console.warn(`⚠️ High latency in step ${stepId}: ${duration.toFixed(0)}ms`);
    }

    return result;
  };
  return workflow;
};

import { Agent } from 'mastra/agents';

const monitorToolCalls = (agent: Agent) => {
  const originalToolCall = agent.toolCall;
  agent.toolCall = async (toolName: string, params: any) => {
    const isStreaming = agent.llmConfig?.streaming ?? false;
    if (!isStreaming) {
      console.error(`🚨 Non-streaming tool call detected: ${toolName}`);
    }

    const start = Date.now();
    const result = await originalToolCall.call(agent, toolName, params);
    const latency = Date.now() - start;

    console.log(`Tool ${toolName} latency: ${latency}ms`);
    return result;
  };
  return agent;
};

import { Memory } from 'mastra/memory';

const auditMemoryContext = (memory: Memory) => {
  const originalRetrieve = memory.retrieve;
  memory.retrieve = async (key: string, maxTokens?: number) => {
    const context = await originalRetrieve.call(memory, key, maxTokens);
    const tokenCount = context.split(/\s+/).length;

    if (tokenCount > 4000) {
      console.error(`💥 Memory context too large: ${tokenCount} tokens for ${key}`);
    }

    return context;
  };
  return memory;
};

