import { Workflow } from 'mastra/workflows';
import { LRUCache } from 'lru-cache';

const cache = new LRUCache<string, any>({ max: 1000 });

const cachedWorkflow = async (workflow: Workflow, stepId: string, input: any) => {
  const promptKey = `workflow:${stepId}:${JSON.stringify(input)}`;

  if (cache.has(promptKey)) {
    console.log('📦 Cache HIT for workflow step');
    return cache.get(promptKey);
  }

  const result = await workflow.executeStep(stepId, input);
  cache.set(promptKey, result);
  return result;
};

