import { Memory } from 'mastra/memory';

const smartMemory = new Memory({
  async retrieve(key: string) {
    const fullContext = await this.storage.get(key);
    if (fullContext.length > 3000) {
      // Parallel summarization
      const summary = await this.summarizeContext(fullContext);
      return summary;
    }
    return fullContext;
  },

  async summarizeContext(context: string) {
    const prompt = `Summarize this conversation (max 1000 tokens):\n${context}`;
    return await this.llm.complete(prompt, { maxTokens: 1000 });
  }
});

